private preferencesService: PreferencesService | null = null;
private historyService: NotificationHistoryService | null = null;
private sendQueues: Map<string, Promise<NotificationResult>> = new Map();

/**
 * Build a NotificationPayload and dispatch to the appropriate adapter.
 * Notifications for the same recipient are serialized in FIFO order to
 * prevent out-of-order delivery (e.g., "payment confirmed" before "order placed").
 */
private send(params: {
  type: NotificationPayload['type'];
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
  /** User ID for preference lookup (falls back to recipient if not provided) */
  recipientUserId?: string;
}): Promise<NotificationResult> {
  const recipientKey = params.recipientUserId ?? params.recipient;
  const previous = this.sendQueues.get(recipientKey) ?? Promise.resolve(undefined as unknown as NotificationResult);
  const current = previous.then(() => this.doSend(params));
  this.sendQueues.set(recipientKey, current);
  return current;
}

private async doSend(params: {
  type: NotificationPayload['type'];
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
  recipientUserId?: string;
}): Promise<NotificationResult> {
  const payload: NotificationPayload = {
    id: generateNotificationId(),
    type: params.type,
    channel: params.channel,
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    createdAt: new Date(),
    metadata: params.metadata,
  };

  // Check user preferences before sending (all channels)
  if (this.preferencesService) {
    const recipientId = params.recipientUserId ?? params.recipient;
    if (!this.preferencesService.shouldSend(recipientId, params.channel, params.type)) {
      this.logger.info(
        `Notification ${payload.id} suppressed by user preferences for ${recipientId} on ${params.channel}`,
      );
      const result: NotificationResult = {
        success: true,
        notificationId: payload.id,
        channel: params.channel,
        deliveredAt: new Date(),
      };
      this.deliveryLog.push(result);
      this.logToHistory(payload, 'suppressed', params.recipientUserId);
      return result;
    }
  }

  this.notifications.push(payload);

  const adapter = this.adapters.get(params.channel);
  if (!adapter) {
    this.logger.warn(`No adapter registered for channel: ${params.channel}`);
    const result: NotificationResult = {
      success: false,
      notificationId: payload.id,
      channel: params.channel,
      deliveredAt: new Date(),
      error: `No adapter registered for channel: ${params.channel}`,
    };
    this.deliveryLog.push(result);
    this.logToHistory(payload, 'failed', params.recipientUserId, result.error);
    return result;
  }

  const result = await adapter.send(payload);
  this.deliveryLog.push(result);
  this.logToHistory(
    payload,
    result.success ? 'delivered' : 'failed',
    params.recipientUserId,
    result.error,
  );
  this.logger.info(
    `Notification ${payload.id} via ${params.channel}: ${result.success ? 'delivered' : 'failed'}`,
  );
  return result;
}

